#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        int arr[15];
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        int *ptr = &arr[n - 1];
        for (int i = 0; i < n; ++i) {
            printf("%d\n", *ptr);
            ptr--;
        }
    }
    return 0;
}

