int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int n;
        cin >> n;
        vector<int> arr(n);
        for (int i = 0; i < n; ++i) cin >> arr[i];
        for (int i = n - 1; i >= 0; --i) {
            cout << arr[i] << '\n';
        }
    }
    return 0;
}

