import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        for i in range(n - 1, -1, -1):
            out_lines.append(str(arr[i]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

